//
// A sub-segment sits underneath the existing value-chain segment
// (Company.comp) and lets admins classify a company more precisely
// for peer comparison (e.g. a 'solar_modules' company can further be
// tagged as TOPCon, HJT, bifacial, BIPV…). When a company covers all
// sub-variants the admin selects every chip. When the parent comp has
// no taxonomic sub-segments, getSubSegmentsForComp() returns [] and
// the UI hides the picker.

export interface SubSegment {
  /** Stable id — 'ss_<code_with_dots_as_underscores>' e.g. ss_1_1_3. */
  id: string
  /** Dotted taxonomy code from the Excel master (e.g. '1.1.3'). */
  code: string
  /** Human-readable product/sub-segment name. */
  name: string
  /** Parent VC-stage code (e.g. '1.1'). */
  stageCode: string
  /** Parent VC-stage label. */
  stageName: string
  /** Industry code (1..15) from the Excel master. */
  industryCode: string
}

export interface TaxonomyStage {
  code: string
  name: string
  industryCode: string
  subs: SubSegment[]
}

