/**
 * Hardcoded CHAIN-node id → Excel stage code. Atlas-added value-chain
 * stage ids (from industry_chain_nodes) inherit the sub-segment pool
 * from their parent industry since they don't round-trip a stage code.
 * If a comp has no stage mapping, the picker falls back to the full
 * industry pool.
 */
export const COMP_TO_STAGE_CODE: Record<string, string> = {
  polysilicon: '1.1',
  silver_paste: '1.1',
  pv_glass: '1.1',
  encapsulants: '1.1',
  al_frame: '1.1',
  backsheet: '1.1',
  junction_box: '1.1',
  bus_ribbon: '1.1',
  mc4_connector: '1.1',
  wafers: '1.2',
  solar_cells: '1.2',
  solar_modules: '1.2',
  inverters: '1.3',
  mounting: '1.3',
  power_transformers: '10.3',
  dist_transformers: '10.3',
  acsr_conductors: '10.3',
  htls: '10.3',
  hv_cables: '10.3',
  switchgear: '10.3',
  smart_meters: '10.3',
  bess: '3.2',
  ems: '12.3',
}

function normSec(sec: string | null | undefined): string {
  return (sec || '').trim().toLowerCase()
}

/** Return the Excel industry code (1..15) for a site sec id, or null. */
export function industryCodeFor(sec: string | null | undefined): string | null {
  const key = normSec(sec)
  if (!key) return null
  return INDUSTRY_ID_TO_CODE[key] ?? null
}

/**
 * Return the sub-segments that belong to the stage that the given
 * (sec, comp) pair points to. If no stage mapping exists, fall back
 * to every sub-segment in the industry so the admin still has a
 * meaningful pool to work from.
 */
export function getSubSegmentsForComp(sec: string | null | undefined, comp: string | null | undefined): SubSegment[] {
  const compKey = (comp || '').trim()
  const stageCode = compKey ? COMP_TO_STAGE_CODE[compKey] : undefined
  if (stageCode) {
    const stage = TAXONOMY_STAGES.find((s) => s.code === stageCode)
    if (stage) return stage.subs
  }
  return getSubSegmentsForIndustry(sec)
}

/** Every sub-segment defined for the given site sec id. */
export function getSubSegmentsForIndustry(sec: string | null | undefined): SubSegment[] {
  const code = industryCodeFor(sec)
  if (!code) return []
  return TAXONOMY_STAGES.filter((s) => s.industryCode === code).flatMap((s) => s.subs)
}

const BY_ID: Record<string, SubSegment> = Object.fromEntries(
  SUB_SEGMENTS.map((s) => [s.id, s])
)

/** Reverse lookup — used by filter chips and table badges site-wide. */
export function getSubSegmentById(id: string): SubSegment | null {
  return BY_ID[id] ?? null
}

/** Human label for a sub-segment id. Unknown ids fall back to the raw id. */
export function getSubSegmentLabel(id: string): string {
  return BY_ID[id]?.name ?? id
}

/**
 * The 15 industries, in the same order as the Excel master. Labels are
 * derived from the first sub-segment's industryCode + a lookup table.
 * Used by the Op Identifier hierarchical value-chain picker.
 */
